function headerScroll(){let t=document.getElementById("header");if(!t)return null;let l=0;return ScrollTrigger.create({start:"top top",end:9999,onUpdate:e=>{e=e.scroll();!(e<=0)&&e>l?t.classList.add("scrolled"):t.classList.remove("scrolled"),l=e}})}function createFilterTab(){document.querySelectorAll(".filter-section").forEach(l=>{let r;var e=l.dataset.target;if(e)r=document.querySelector(e);else if(!(r=l.querySelector(".filter-section-result"))&&!(r=l.nextElementSibling)?.classList.contains("filter-section-result"))return;if(r){var e=l.querySelectorAll(".filter-button[data-type]"),a=l.querySelector(".filter-button.active");if(a){let t=a.dataset.type;"all"!==t&&r.querySelectorAll(".filter-item").forEach(e=>{e.style.display=e.classList.contains(t)?"":"none"})}e.forEach(e=>{e.addEventListener("click",function(){l.querySelectorAll(".filter-button").forEach(e=>e.classList.remove("active")),this.classList.add("active");let t=this.dataset.type,e=r.querySelectorAll(".filter-item");gsap.timeline().to(r,{autoAlpha:0,duration:.3}).call(()=>{e.forEach(e=>{"all"===t?e.style.display="":e.style.display=e.classList.contains(t)?"":"none"})}).to(r,{autoAlpha:1,duration:.3})})})}})}export{headerScroll,createFilterTab};